package com.evenodd;

public class Task1EvenOdd {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
       int number=43;
       {
    	if(number%2==0)   {
       
       System.out.println("number is even"+number);
       }
    	else{
    		System.out.println("number is odd"+number);
    	}
    	
    	switch (number) {
    	case 1:
    		System.out.println("number is even"+number);
    		break;
    	case -1:
    		System.out.println("number is odd"+number);
    		break;
    		
    			
    	
    }
   }
  }
 }

	



